// MARK: - Deep Link Navigator

class DeepLinkNavigator {
    
    static let shared = DeepLinkNavigator()
    
    private init() {}
    
    weak var window: UIWindow?
    
    /// Handles a universal link URL and navigates to the appropriate view controller.
    /// - Parameter url: The universal link URL to handle.
    /// - Returns: `true` if the link was handled successfully; `false` otherwise.
    @discardableResult
    func handleUniversalLink(_ url: URL) -> Bool {
        let route = UniversalLinkParser.parse(url: url)
        
        print("[DeepLinkNavigator] Handling route: \(route.description)")
        
        // Track analytics for marketing campaigns and email notifications
        trackDeepLink(url: url, route: route)
        
        guard let rootViewController = findRootNavigationController() else {
            // Defer navigation if the app hasn't finished launching
            pendingRoute = route
            return route != .unknown
        }
        
        return navigate(to: route, using: rootViewController)
    }
    
    /// Handles any pending deep link route deferred during app launch.
    func handlePendingRouteIfNeeded() {
        guard let route = pendingRoute,
              let navController = findRootNavigationController() else {
            return
        }
        pendingRoute = nil
        navigate(to: route, using: navController)
    }
    
    // MARK: - Private
    
    private var pendingRoute: DeepLinkRoute?
    
    @discardableResult
    private func navigate(to route: DeepLinkRoute, using navigationController: UINavigationController) -> Bool {
        switch route {
        case .profile(let userID):
            let profileVC = ProfileViewController()
            profileVC.userID = userID
            navigationController.pushViewController(profileVC, animated: true)
            return true
            
        case .paymentConfirm(let transactionID):
            let paymentVC = PaymentConfirmViewController()
            paymentVC.transactionID = transactionID
            navigationController.pushViewController(paymentVC, animated: true)
            return true
            
        case .adminSettings:
            // Check if user has admin privileges before navigating
            guard isUserAdmin() else {
                showAccessDeniedAlert(on: navigationController)
                return false
            }
            let adminVC = AdminSettingsViewController()
            navigationController.pushViewController(adminVC, animated: true)
            return true
            
        case .unknown:
            print("[DeepLinkNavigator] Unknown route, not handling.")
            return false
        }
    }
    
    private func findRootNavigationController() -> UINavigationController? {
        guard let window = window ?? UIApplication.shared.connectedScenes
            .compactMap({ ($0 as? UIWindowScene)?.windows.first })
            .first else {
            return nil
        }
        
        if let navController = window.rootViewController as? UINavigationController {
            return navController
        }
        
        if let tabBarController = window.rootViewController as? UITabBarController,
           let navController = tabBarController.selectedViewController as? UINavigationController {
            return navController
        }
        
        // If root is presented modally wrapped in nav
        if let presented = window.rootViewController?.presentedViewController as? UINavigationController {
            return presented
        }
        
        return nil
    }
    
    private func isUserAdmin() -> Bool {
        // Replace with actual auth/role check
        return UserDefaults.standard.bool(forKey: "isAdminUser")
    }
    
    private func showAccessDeniedAlert(on viewController: UIViewController) {
        let alert = UIAlertController(
            title: "Access Denied",
            message: "You do not have admin privileges to access this section.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        viewController.present(alert, animated: true)
    }
    
    private func trackDeepLink(url: URL, route: DeepLinkRoute) {
        // Extract UTM parameters for marketing campaign tracking
        let components = URLComponents(url: url, resolvingAgainstBaseURL: true)
        let queryItems = components?.queryItems ?? []
        
        let utmSource = queryItems.first(where: { $0.name == "utm_source" })?.value
        let utmMedium = queryItems.first(where: { $0.name == "utm_medium" })?.value
        let utmCampaign = queryItems.first(where: { $0.name == "utm_campaign" })?.value
        
        var analyticsPayload: [String: String] = [
            "route": route.description,
            "url": url.absoluteString
        ]
        
        if let source = utmSource { analyticsPayload["utm_source"] = source }
        if let medium = utmMedium { analyticsPayload["utm_medium"] = medium }
        if let campaign = utmCampaign { analyticsPayload["utm_campaign"] = campaign }
        
        print("[Analytics] Deep link tracked: \(analyticsPayload)")
        // Send to your analytics service here
    }
}

// MARK: - SceneDelegate Integration

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }
        
        let window = UIWindow(windowScene: windowScene)
        
        let homeVC = UIViewController()
        homeVC.view.backgroundColor = .systemBackground
        homeVC.title = "Home"
        
        let navigationController = UINavigationController(rootViewController: homeVC)
        
        window.rootViewController = navigationController
        window.makeKeyAndVisible()
        self.window = window
        
        // Register navigator's window reference
        DeepLinkNavigator.shared.window = window
        
        // Handle universal link if app was launched via one
        if let userActivity = connectionOptions.userActivities.first,
           userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            DeepLinkNavigator.shared.handleUniversalLink(url)
        }
        
        // Handle pending route after UI is ready
        DeepLinkNavigator.shared.handlePendingRouteIfNeeded()
    }
    
    // Called when a universal link is received while the app is running
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        
        DeepLinkNavigator.shared.handleUniversalLink(url)
    }
}

